package com.tuapp.clientesimport android.content.ContentValuesimport android.content.Contextimport android.database.sqlite.SQLiteDatabaseimport android.database.sqlite.SQLiteOpenHelperclass DatabaseHelper(context: Context) : SQLiteOpenHelper(context, DATABASE_NAME, null, DATABASE_VERSION) {    companion object {        private const val DATABASE_NAME = "clientes.db"        private const val DATABASE_VERSION = 1        private const val TABLE_NAME = "clientes"        private const val COLUMN_ID = "id"        private const val COLUMN_NOMBRE = "nombre"        private const val COLUMN_TELEFONO = "telefono"        private const val COLUMN_EMAIL = "email"    }    override fun onCreate(db: SQLiteDatabase) {        val createTable = """            CREATE TABLE $TABLE_NAME (                $COLUMN_ID INTEGER PRIMARY KEY AUTOINCREMENT,                $COLUMN_NOMBRE TEXT NOT NULL,                $COLUMN_TELEFONO TEXT NOT NULL,                $COLUMN_EMAIL TEXT            )        """.trimIndent()        db.execSQL(createTable)    }    override fun onUpgrade(db: SQLiteDatabase, oldVersion: Int, newVersion: Int) {        db.execSQL("DROP TABLE IF EXISTS $TABLE_NAME")        onCreate(db)    }    fun insertarCliente(nombre: String, telefono: String, email: String): Long {        val values = ContentValues().apply {            put(COLUMN_NOMBRE, nombre)            put(COLUMN_TELEFONO, telefono)            put(COLUMN_EMAIL, email)        }        return writableDatabase.insert(TABLE_NAME, null, values)    }    fun obtenerClientes(): List<Cliente> {        val lista = mutableListOf<Cliente>()        val cursor = readableDatabase.query(TABLE_NAME, null, null, null, null, null, null)        with(cursor) {            while (moveToNext()) {                val id = getInt(getColumnIndexOrThrow(COLUMN_ID))                val nombre = getString(getColumnIndexOrThrow(COLUMN_NOMBRE))                val telefono = getString(getColumnIndexOrThrow(COLUMN_TELEFONO))                val email = getString(getColumnIndexOrThrow(COLUMN_EMAIL))                lista.add(Cliente(id, nombre, telefono, email))            }        }        cursor.close()        return lista    }}data class Cliente(val id: Int, val nombre: String, val telefono: String, val email: String)
